sys_script_include.script:
var DOTTCTMPUtils = Class.create();
DOTTCTMPUtils.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
	// 過去の申請情報を取得
	getPastAppInfo: function () {
		var appSysId = this.getParameter("sysparm_sysId");
		var gr = new GlideRecord("x_1447708_dottctmp_dot_applicant");
		var questions = [
			"work_app_type",
			"reason",
			"is_coordinated",
			"target_date",
			"start_time",
			"end_time",
			"worked_day",
			"start_working_time",
			"end_working_time",
			"worked_day",
			"replacement_holiday",
			"remarks",
			"approver"
		];
		var pastAppInfo = {};
		if (gr.get(appSysId)) {
			for (var question of questions) {
				gs.info(question);
				pastAppInfo[question] = gr.variables[question].toString();
			}
		}

		return JSON.stringify(pastAppInfo);
	},
	// 対象日が現在より過去か未来かチェックする
	validateDateTime: function(){
		var dateTime = this.getParameter("sysparm_dateTime");
		gs.info(GlideDateTime(dateTime));
	},
	type: 'DOTTCTMPUtils'
});
